const SOPS = {
  'SOP-01': 'Vérification alarmes supervision — identifier et acquitter les alarmes actives',
  'SOP-02': 'Analyse logs supervision — isoler la source de l\'alarme',
  'SOP-03': 'Test OTDR — localiser une rupture ou dégradation fibre optique',
  'SOP-04': 'Rebouclage port optique — vérifier la continuité du lien',
  'SOP-05': 'Remplacement module SFP/XFP défectueux',
  'SOP-06': 'Vérification alimentation — PSU principal et redondant',
  'SOP-07': 'Réinitialisation logicielle équipement (soft reset)',
  'SOP-08': 'Basculement OOB — activation accès hors bande de secours',
  'SOP-09': 'Escalade NOC niveau 2 — ouverture ticket P1/P2',
  'SOP-10': 'Procédure crise — activation cellule de crise NOC',
  'SOP-11': 'Remplacement carte ligne / carte de service',
  'SOP-12': 'Remplacement châssis — procédure de swap à froid',
  'SOP-13': 'Coordination prestataire terrain — dispatch technicien on-site',
};

const body = $input.first().json.body || $input.first().json;
const { incident_id, incident_type, criticite, sops, site, equipment, technicien, date_intervention, heure_debut } = body;

const sopRows = (sops || []).map(s => {
  const desc = SOPS[s] || `Procédure ${s}`;
  return `<tr><td class="sop-id">${s}</td><td>${desc}</td><td class="checkbox">☐ Fait</td></tr>`;
}).join('\n');

const criticiteClass = { MINEUR: 'crit-mineur', MAJEUR: 'crit-majeur', CRITIQUE: 'crit-critique' }[criticite] || '';
const dateStr = date_intervention || new Date().toISOString().slice(0, 10);
const heureStr = heure_debut || '--:--';
const genTime = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
const filename = `mop-${incident_id}.pdf`;

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 10.5pt; color: #222; background: #fff; padding: 18mm 20mm; }
  h1 { font-size: 18pt; color: #0d2b52; border-bottom: 3px solid #0d2b52; padding-bottom: 6px; margin-bottom: 14px; letter-spacing: 0.5px; }
  h2 { font-size: 11pt; color: #0d2b52; margin: 18px 0 8px; text-transform: uppercase; letter-spacing: 0.3px; }
  .meta-block { background: #f0f5fb; border-left: 4px solid #0d2b52; padding: 10px 14px; margin-bottom: 18px; border-radius: 2px; }
  .meta-grid { display: grid; grid-template-columns: 130px 1fr 130px 1fr; gap: 4px 8px; }
  .meta-label { font-weight: bold; color: #555; font-size: 9.5pt; }
  .meta-val { color: #222; }
  .crit-mineur  { color: #2e7d32; font-weight: bold; }
  .crit-majeur  { color: #e65100; font-weight: bold; }
  .crit-critique{ color: #b71c1c; font-weight: bold; background: #fff3f3; padding: 1px 4px; border-radius: 2px; }
  table.sop-table { width: 100%; border-collapse: collapse; margin-top: 4px; }
  table.sop-table th { background: #0d2b52; color: #fff; padding: 7px 10px; text-align: left; font-size: 10pt; }
  table.sop-table td { padding: 6px 10px; border-bottom: 1px solid #dde4ef; vertical-align: top; }
  table.sop-table tr:nth-child(even) td { background: #f7f9fc; }
  .sop-id { font-weight: bold; color: #0d2b52; white-space: nowrap; width: 80px; }
  .checkbox { text-align: center; width: 80px; font-size: 13pt; color: #888; }
  .sig-block { margin-top: 30px; display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; }
  .sig-box { border: 1px solid #bbb; padding: 8px 12px; min-height: 60px; border-radius: 2px; }
  .sig-label { font-size: 9pt; color: #777; margin-bottom: 4px; }
  .footer { margin-top: 24px; font-size: 8.5pt; color: #aaa; border-top: 1px solid #ddd; padding-top: 6px; text-align: right; }
</style>
</head>
<body>
<h1>MOP — Procédure de Maintenance et d\'Exploitation</h1>

<div class="meta-block">
  <div class="meta-grid">
    <span class="meta-label">Incident ID</span><span class="meta-val">${incident_id || 'N/A'}</span>
    <span class="meta-label">Site</span><span class="meta-val">${site || 'N/A'}</span>
    <span class="meta-label">Type incident</span><span class="meta-val">${incident_type || 'N/A'}</span>
    <span class="meta-label">Équipement</span><span class="meta-val">${equipment || 'N/A'}</span>
    <span class="meta-label">Criticité</span><span class="meta-val"><span class="${criticiteClass}">${criticite || 'N/A'}</span></span>
    <span class="meta-label">Technicien</span><span class="meta-val">${technicien || 'N/A'}</span>
    <span class="meta-label">Date</span><span class="meta-val">${dateStr}</span>
    <span class="meta-label">Heure début</span><span class="meta-val">${heureStr}</span>
  </div>
</div>

<h2>Procédures applicables — ${(sops || []).length} SOP(s)</h2>
<table class="sop-table">
  <thead><tr><th>SOP</th><th>Description</th><th>Validation</th></tr></thead>
  <tbody>${sopRows}</tbody>
</table>

<div class="sig-block">
  <div class="sig-box"><div class="sig-label">Technicien intervenant</div></div>
  <div class="sig-box"><div class="sig-label">Responsable NOC</div></div>
  <div class="sig-box"><div class="sig-label">Clôture — heure fin</div></div>
</div>

<div class="footer">Généré automatiquement par MOP Machinery — ${genTime}</div>
</body>
</html>`;

const buf = Buffer.from(html, 'utf8');
return [{
  json: { incident_id, filename },
  binary: {
    'index.html': {
      data: buf.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
